INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (4, "2019/07/31 12:00:00", 110501, 0.0, 0.0, 0.0, 24015, 4, 1, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (4, "2019/07/31 12:00:00", 110501, 0.0, 4.0, 0.0, 24016, 1, 2, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (4, "2019/07/31 12:00:00", 110501, 0.0, 0.0, 0.0, 24017, 4, 3, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (1, "2019/07/31 12:00:00", 110501, 0.0, 5.2, 0.0, 24018, 2, 4, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (5, "2019/07/31 12:00:00", 110501, 0.0, 4.2, 0.0, 24019, 6, 5, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "2019/07/31 12:00:00", 110501, 0.0, 0.0, 0.0, 24020, 2, 6, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (1, "2019/07/31 12:00:00", 110501, 0.0, 6.4, 0.0, 24021, 6, 7, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "2019/07/31 12:00:00", 110501, 0.0, 0.0, 0.0, 24022, 2, 8, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (6, "2019/07/31 12:00:00", 110501, 0.0, 10.08, 0.0, 24023, 3, 9, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (1, "2019/07/31 12:00:00", 110501, 0.0, 5.0, 0.0, 24024, 2, 10, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (2, "2019/07/31 12:00:00", 110501, 0.0, 0.0, 0.0, 24025, 2, 11, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 24, "カオリ（サマー）", "2030/12/17 14:59:59", 10021);
